// Hand-authored governed request path — the engine behind every billed
// Scrape.do call (scrape, google *, batch). Hand file (no "Generated by ...
// DO NOT EDIT" header) so it survives regeneration.
//
// Every billed call goes through runGoverned, which:
//   1. resolves the billing MODE and pre-flight credit cost,
//   2. enforces the optional spend ceiling (--max-credits / saved budget),
//   3. acquires a cross-process concurrency LEASE capped at the plan's live
//      ConcurrentRequest (so N agent processes never exceed the account cap),
//   4. issues the request, retrying only the NON-BILLED 429/502/510 classes,
//   5. debits the local credit LEDGER from the authoritative
//      `Scrape.do-Request-Cost` response header (falling back to the estimate),
//   6. releases the lease.
//
// Under `PRINTING_PRESS_VERIFY=1` it never touches the network or spends
// credits (returns a synthetic empty body); under `PRINTING_PRESS_DOGFOOD=1`
// it makes real calls but curtails retries to fit the live matrix timeout.

package cli

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/mvanhorn/printing-press-library/library/developer-tools/scrape-do/internal/cliutil"
	"github.com/mvanhorn/printing-press-library/library/developer-tools/scrape-do/internal/config"
	"github.com/mvanhorn/printing-press-library/library/developer-tools/scrape-do/internal/store"
)

// Billing modes and their base credit cost (per the Scrape.do request-cost
// table). Domain overrides (see domainOverrideCost) supersede these.
const (
	modeDatacenter       = "datacenter"
	modeDatacenterRender = "datacenter+render"
	modeSuper            = "super"
	modeSuperRender      = "super+render"
	modeGoogle           = "google"
)

// baseModeCost returns the credit cost for a resolved mode label, ignoring
// domain overrides.
func baseModeCost(mode string) int {
	switch mode {
	case modeDatacenter:
		return 1
	case modeDatacenterRender:
		return 5
	case modeSuper:
		return 10
	case modeSuperRender:
		return 25
	case modeGoogle:
		return 10
	default:
		return 1
	}
}

// resolveScrapeMode maps the render/super toggles to a billing mode label.
func resolveScrapeMode(render, super bool) string {
	switch {
	case super && render:
		return modeSuperRender
	case super:
		return modeSuper
	case render:
		return modeDatacenterRender
	default:
		return modeDatacenter
	}
}

// domainOverrides lists the documented per-domain credit costs that supersede
// the proxy/render matrix. Keys are matched as host suffixes (case-insensitive).
var domainOverrides = map[string]int{
	"linkedin.com":     30,
	"shopee.com":       100,
	"sainsburys.co.uk": 200,
}

// domainOverrideCost returns a per-domain credit override for a target URL's
// host, if one is documented.
func domainOverrideCost(rawURL string) (int, string, bool) {
	u, err := url.Parse(rawURL)
	if err != nil || u.Host == "" {
		return 0, "", false
	}
	host := strings.ToLower(u.Hostname())
	for suffix, cost := range domainOverrides {
		if host == suffix || strings.HasSuffix(host, "."+suffix) {
			return cost, suffix, true
		}
	}
	return 0, "", false
}

// estimateScrapeCost computes the pre-flight credit cost for a target scrape.
// host-based domain overrides win over the proxy/render matrix.
func estimateScrapeCost(rawURL string, render, super bool) (int, string) {
	if cost, dom, ok := domainOverrideCost(rawURL); ok {
		return cost, "domain:" + dom
	}
	mode := resolveScrapeMode(render, super)
	return baseModeCost(mode), mode
}

// scrapeRequest is a resolved, ready-to-dispatch billed call.
type scrapeRequest struct {
	kind       string            // "scrape" | "google:search" | "google:maps" | ...
	path       string            // "/" | "/plugin/google/search"
	params     map[string]string // query params (token added by the governor)
	target     string            // display label (url or query)
	family     string            // attribution key (host or query family)
	mode       string            // billing mode label
	estCost    int               // pre-flight credit estimate
	agent      string            // attribution id (--agent-id / SCRAPEDO_AGENT_ID)
	maxCredits int               // per-call ceiling override (0 = use saved budget)
}

// scrapeResult is the outcome of a governed call.
type scrapeResult struct {
	Body             []byte `json:"-"`
	Status           int    `json:"status"`
	Cost             int    `json:"cost"`
	CostSource       string `json:"cost_source"`
	RemainingCredits int    `json:"remaining_credits,omitempty"`
	Mode             string `json:"mode"`
	Synthetic        bool   `json:"synthetic,omitempty"`
}

// govHTTPClient builds an HTTP client honoring the request timeout.
func (f *rootFlags) govHTTPClient() *http.Client {
	to := f.timeout
	if to <= 0 {
		to = 60 * time.Second
	}
	return &http.Client{Timeout: to}
}

// agentID resolves the attribution id from the flag value or the
// SCRAPEDO_AGENT_ID environment variable.
func resolveAgentID(flagVal string) string {
	if flagVal != "" {
		return flagVal
	}
	return strings.TrimSpace(os.Getenv("SCRAPEDO_AGENT_ID"))
}

// retriableStatus reports whether an HTTP status is a non-billed, retriable
// Scrape.do failure (concurrency / transient / client-cancel).
func retriableStatus(code int) bool {
	return code == http.StatusTooManyRequests || code == 502 || code == 510
}

// runGoverned executes a billed Scrape.do request through the full governor.
// It returns the result and records the call to the local ledger. The caller
// owns interpreting the body.
func (f *rootFlags) runGoverned(ctx context.Context, ext *store.ScrapeExtras, req scrapeRequest) (*scrapeResult, error) {
	cfg, err := config.Load(f.configPath)
	if err != nil {
		return nil, configErr(err)
	}
	if cfg.ScrapedoApiKey == "" {
		return nil, configErr(fmt.Errorf("no API token configured; set SCRAPEDO_API_KEY (see 'scrape-do-pp-cli doctor')"))
	}

	// Verify mode: never spend credits or touch the network.
	if cliutil.IsVerifyEnv() {
		return &scrapeResult{Status: 200, Cost: 0, CostSource: "synthetic", Mode: req.mode, Synthetic: true, Body: syntheticBody(req.kind)}, nil
	}

	now := time.Now()

	// Atomically reserve the estimated cost against the spend ceiling. The
	// reservation is a pending ledger debit that concurrent batch workers
	// serialize on, so the ceiling cannot be over-granted by N workers.
	// reservationID == 0 means no ceiling is configured (no reservation needed).
	reservationID, rerr := f.reserveSpend(ctx, ext, req, now)
	if rerr != nil {
		return nil, rerr
	}

	// Concurrency lease, capped at the plan's live ConcurrentRequest.
	cap := f.concurrencyCap(ctx, ext, cfg)
	leaseID, err := f.acquireLeaseBlocking(ctx, ext, req.agent, cap, now)
	if err != nil {
		_ = ext.CancelReservation(context.Background(), reservationID)
		return nil, err
	}
	defer func() { _ = ext.ReleaseLease(context.Background(), leaseID) }()

	res, callErr := f.dispatch(ctx, cfg, req)

	// Record the call to the ledger. Cost is the authoritative header value
	// when present, otherwise the pre-flight estimate. 401/429/502/510 are
	// not billed, so cost is 0 there.
	rec := store.CallRecord{
		Kind: req.kind, Target: req.target, Mode: req.mode, Agent: req.agent,
		Family: req.family, At: now,
	}
	if res != nil {
		rec.HTTPStatus = res.Status
		rec.Cost = res.Cost
		rec.CostSource = res.CostSource
		rec.RemainingCredits = -1
		if res.RemainingCredits > 0 {
			rec.RemainingCredits = res.RemainingCredits
		}
		rec.Bytes = len(res.Body)
		rec.OK = callErr == nil && res.Status >= 200 && res.Status < 300
	} else {
		rec.RemainingCredits = -1
	}
	if callErr != nil {
		rec.Err = scrubToken(callErr.Error(), cfg.ScrapedoApiKey)
	}
	// Reconcile the reservation to the authoritative cost (or record fresh when
	// no ceiling was configured). Detached context so a billed call is still
	// recorded even if the request context was cancelled mid-flight.
	if reservationID > 0 {
		_ = ext.ReconcileReservation(context.Background(), reservationID, rec)
	} else {
		_ = ext.RecordCall(context.Background(), rec) // best-effort: never fail a scrape on ledger write
	}

	if callErr != nil {
		return res, callErr
	}
	return res, nil
}

// buildRequestURL composes the full Scrape.do request URL from the request
// params plus the configured token. The configured token is applied LAST and
// `token` is skipped inside the param loop, so a user-supplied `--param
// token=...` can never override the real API key (which would send the wrong
// token and leak the injected value into the ledger error column).
func buildRequestURL(cfg *config.Config, req scrapeRequest) string {
	vals := url.Values{}
	for k, v := range req.params {
		if strings.EqualFold(k, "token") || v == "" {
			continue
		}
		vals.Set(k, v)
	}
	vals.Set("token", cfg.ScrapedoApiKey)
	base := strings.TrimRight(cfg.BaseURL, "/")
	return base + req.path + "?" + vals.Encode()
}

// dispatch issues the HTTP request with retry on the non-billed failure
// classes, parses the cost headers, and returns the result.
func (f *rootFlags) dispatch(ctx context.Context, cfg *config.Config, req scrapeRequest) (*scrapeResult, error) {
	full := buildRequestURL(cfg, req)

	client := f.govHTTPClient()
	maxAttempts := 3
	if cliutil.IsDogfoodEnv() {
		maxAttempts = 1 // curtail under the live matrix timeout
	}

	var last *scrapeResult
	for attempt := 1; attempt <= maxAttempts; attempt++ {
		httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, full, nil)
		if err != nil {
			// A malformed base URL makes NewRequestWithContext fail with the
			// full token-bearing URL in the message — scrub it too.
			return nil, fmt.Errorf("%s", scrubToken(err.Error(), cfg.ScrapedoApiKey))
		}
		resp, err := client.Do(httpReq)
		if err != nil {
			// The transport error (*url.Error) embeds the full request URL,
			// which carries the token query param — scrub it before it can
			// reach stderr, the JSON envelope, or the credit ledger.
			return nil, classifyAPIError(fmt.Errorf("%s", scrubToken(err.Error(), cfg.ScrapedoApiKey)), f)
		}
		body, _ := io.ReadAll(resp.Body)
		_ = resp.Body.Close()

		r := &scrapeResult{Status: resp.StatusCode, Mode: req.mode, Body: body}
		if cs := resp.Header.Get("Scrape.do-Request-Cost"); cs != "" {
			if n, perr := strconv.Atoi(strings.TrimSpace(cs)); perr == nil {
				r.Cost, r.CostSource = n, "header"
			}
		}
		if r.CostSource == "" {
			if resp.StatusCode >= 200 && resp.StatusCode < 300 {
				r.Cost, r.CostSource = req.estCost, "estimate"
			} else {
				r.Cost, r.CostSource = 0, "unbilled"
			}
		}
		if rc := resp.Header.Get("Scrape.do-Remaining-Credits"); rc != "" {
			if n, perr := strconv.Atoi(strings.TrimSpace(rc)); perr == nil {
				r.RemainingCredits = n
			}
		}
		last = r

		if retriableStatus(resp.StatusCode) && attempt < maxAttempts {
			backoff := time.Duration(attempt) * 750 * time.Millisecond
			select {
			case <-ctx.Done():
				return last, ctx.Err()
			case <-time.After(backoff):
			}
			continue
		}
		break
	}

	if last == nil {
		return nil, fmt.Errorf("scrape.do: no response")
	}
	switch last.Status {
	case 401:
		return last, &cliError{code: 4, err: fmt.Errorf("scrape.do 401: invalid token or out of credits (check 'scrape-do-pp-cli budget')")}
	case http.StatusTooManyRequests:
		return last, &cliError{code: 5, err: &cliutil.RateLimitError{URL: "scrape.do " + req.target, Body: "concurrency limit exceeded (429); retries exhausted — back off or raise the plan's concurrent-request cap"}}
	}
	if last.Status >= 500 {
		return last, &cliError{code: 5, err: fmt.Errorf("scrape.do %d: upstream failure (not billed)", last.Status)}
	}
	return last, nil
}

// concurrencyCap returns the plan's concurrent-request ceiling, refreshing the
// cached /info snapshot when it is missing or stale.
func (f *rootFlags) concurrencyCap(ctx context.Context, ext *store.ScrapeExtras, cfg *config.Config) int {
	if u, err := ext.LatestUsage(ctx); err == nil && u != nil && time.Since(u.CapturedAt) < 10*time.Minute {
		if u.ConcurrentRequest > 0 {
			return u.ConcurrentRequest
		}
	}
	if u, err := fetchInfo(ctx, cfg, f.govHTTPClient()); err == nil {
		_ = ext.SaveUsage(ctx, u)
		if u.ConcurrentRequest > 0 {
			return u.ConcurrentRequest
		}
	}
	return 5 // free-tier default when /info is unavailable
}

// acquireLeaseBlocking polls AcquireLease until a slot frees or the context /
// deadline expires.
func (f *rootFlags) acquireLeaseBlocking(ctx context.Context, ext *store.ScrapeExtras, agent string, cap int, now time.Time) (int64, error) {
	deadline := now.Add(2 * time.Minute)
	for {
		id, ok, _, err := ext.AcquireLease(ctx, agent, cap, time.Now())
		if err != nil {
			return 0, err
		}
		if ok {
			return id, nil
		}
		if time.Now().After(deadline) {
			return 0, &cliError{code: 5, err: fmt.Errorf("could not acquire a concurrency slot within timeout (plan cap %d in use by other agents)", cap)}
		}
		select {
		case <-ctx.Done():
			return 0, ctx.Err()
		case <-time.After(250 * time.Millisecond):
		}
	}
}

// reserveSpend resolves the effective ceiling (per-call --max-credits or the
// saved budget) and atomically reserves the estimated cost. Returns the
// reservation id (0 when no ceiling is configured) or a ceiling-reached error.
// Fail-open on a ledger error: never block a scrape on a storage failure.
func (f *rootFlags) reserveSpend(ctx context.Context, ext *store.ScrapeExtras, req scrapeRequest, now time.Time) (int64, error) {
	ceiling := req.maxCredits
	if ceiling <= 0 {
		if b, err := ext.GetBudget(ctx); err == nil && b.MaxCredits.Valid {
			ceiling = int(b.MaxCredits.Int64)
		}
	}
	if ceiling <= 0 {
		return 0, nil
	}
	monthStart := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
	id, ok, total, err := ext.ReserveSpend(ctx, monthStart, ceiling, req.estCost, req.mode, req.agent, req.family, now)
	if err != nil {
		return 0, nil
	}
	if !ok {
		return 0, &cliError{code: 4, err: fmt.Errorf("spend ceiling reached: this call (~%d credits) would push month-to-date spend (%d) past the %d-credit ceiling", req.estCost, total, ceiling)}
	}
	return id, nil
}

// fetchInfo calls the free /info endpoint and parses the account state.
func fetchInfo(ctx context.Context, cfg *config.Config, client *http.Client) (store.UsageSnapshot, error) {
	var u store.UsageSnapshot
	if cfg.ScrapedoApiKey == "" {
		return u, fmt.Errorf("no API token configured")
	}
	full := strings.TrimRight(cfg.BaseURL, "/") + "/info?token=" + url.QueryEscape(cfg.ScrapedoApiKey)
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, full, nil)
	if err != nil {
		return u, fmt.Errorf("%s", scrubToken(err.Error(), cfg.ScrapedoApiKey))
	}
	resp, err := client.Do(httpReq)
	if err != nil {
		return u, fmt.Errorf("%s", scrubToken(err.Error(), cfg.ScrapedoApiKey))
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != 200 {
		return u, fmt.Errorf("/info returned %d", resp.StatusCode)
	}
	var raw struct {
		IsActive                   bool
		ConcurrentRequest          int
		RemainingConcurrentRequest int
		MaxMonthlyRequest          int
		RemainingMonthlyRequest    int
	}
	if err := json.Unmarshal(body, &raw); err != nil {
		return u, fmt.Errorf("parse /info: %w", err)
	}
	u = store.UsageSnapshot{
		IsActive:            raw.IsActive,
		ConcurrentRequest:   raw.ConcurrentRequest,
		RemainingConcurrent: raw.RemainingConcurrentRequest,
		MaxMonthly:          raw.MaxMonthlyRequest,
		RemainingMonthly:    raw.RemainingMonthlyRequest,
		CapturedAt:          time.Now(),
	}
	return u, nil
}

// openExtras opens the local DB (creating the governor + SERP schema lazily)
// and returns the store plus the governor wrapper. Caller must Close the store.
func openExtras(ctx context.Context, dbPath string) (*store.Store, *store.ScrapeExtras, error) {
	if dbPath == "" {
		dbPath = defaultDBPath("scrape-do-pp-cli")
	}
	st, err := store.OpenWithContext(ctx, dbPath)
	if err != nil {
		return nil, nil, fmt.Errorf("opening database: %w", err)
	}
	ext := store.NewScrapeExtras(st.DB())
	if err := ext.EnsureScrapedoSchema(ctx); err != nil {
		_ = st.Close()
		return nil, nil, err
	}
	return st, ext, nil
}

// scrubToken redacts the API token from any string before it can reach a log,
// error envelope, or the on-disk ledger. Transport errors wrap the request URL,
// which carries the token as a query param, so this guards the Cardinal Rule
// that the token value never appears in any artifact.
func scrubToken(s, token string) string {
	if token == "" {
		return s
	}
	return strings.ReplaceAll(s, token, "***")
}

// syntheticBody returns a minimal valid body for verify mode so output
// formatting still exercises without a real API call.
func syntheticBody(kind string) []byte {
	if strings.HasPrefix(kind, "google") {
		return []byte(`{"organic_results":[],"search_information":{},"search_parameters":{}}`)
	}
	return []byte("")
}
